// // This module decrements its value on each positive edge of the clock signal. When the reset signal is asserted (low), the counter resets to zero. Otherwise, the counter continues to decrement, wrapping around after reaching the minimum value of 0.
module top_module(
    input clk,
    input rst,
    output reg [3:0] count
);always @(posedge clk) begin
    if (rst) begin
        count <= 4'b0;
    end else begin
        count <= count + 1;
    end
end

endmodule
